func (wb *WriteBatch) commit() error {
	if wb.err != nil {
		return wb.err
	}
	wb.wg.Add(1)
	wb.txn.CommitWith(wb.callback)
	wb.txn = wb.db.newTransaction(true, true)
	wb.txn.readTs = wb.db.orc.readMark.DoneUntil()
	return wb.err
}

