func (g *Group) Add(f Func, schedule Schedule) *Task {
	i := len(g.tasks)
	g.tasks = append(g.tasks, Task{
		f:        f,
		schedule: schedule,
		reset:    make(chan struct{}, 16),
	})
	return &g.tasks[i]
}

func (g *Group) Start() {
	ctx := context.Background()
	ctx, g.cancel = context.WithCancel(ctx)
	g.wg.Add(len(g.tasks))

	g.mu.Lock()
	if g.running == nil {
		g.running = make(map[int]bool)
	}
	g.mu.Unlock()

	for i := range g.tasks {
		g.mu.Lock()
		if g.running[i] {
			g.mu.Unlock()
			continue
		}

		g.running[i] = true
		task := g.tasks[i]
		g.mu.Unlock()

		go func(i int) {
			task.loop(ctx)
			g.wg.Done()

			g.mu.Lock()
			g.running[i] = false
			g.mu.Unlock()
		}(i)
	}
}

