func RegisterStmt(sql string) int {
	code := len(stmts)
	stmts[code] = sql
	return code
}

func PrepareStmts(db *sql.DB) (map[int]*sql.Stmt, error) {
	index := map[int]*sql.Stmt{}

	for code, sql := range stmts {
		stmt, err := db.Prepare(sql)
		if err != nil {
			return nil, errors.Wrapf(err, "%q", sql)
		}
		index[code] = stmt
	}

	return index, nil
}

