func (m *Method) Generate(buf *file.Buffer) error {
	if strings.HasSuffix(m.kind, "Ref") {
		return m.ref(buf)
	}
	switch m.kind {
	case "URIs":
		return m.uris(buf)
	case "List":
		return m.list(buf)
	case "Get":
		return m.get(buf)
	case "ID":
		return m.id(buf)
	case "Exists":
		return m.exists(buf)
	case "Create":
		return m.create(buf)
	case "Rename":
		return m.rename(buf)
	case "Update":
		return m.update(buf)
	case "Delete":
		return m.delete(buf)
	default:
		return fmt.Errorf("Unknown method kind '%s'", m.kind)
	}
}

