	}
	creds.VaultToken, err = readSecretFile("/amazon-vault-token")
	if err != nil && !os.IsNotExist(err) {
		return nil, err
	}

	distribution, err := readSecretFile("/amazon-distribution")
	return NewAmazonClient(region, bucket, &creds, distribution, reversed...)
}

