	if flags.Deterministic {
		p = 0xdeadf00f
	}
	return fmt.Sprintf("⟪0x%x⟫", p)
}

func (m visitedPointers) Visit(v reflect.Value) bool {
	p := value.PointerOf(v)
	_, visited := m[p]
	m[p] = struct{}{}
	return visited
