func ParseTag(s string) Tag {
	var name string
	var omitzero bool
	var omitempty bool

	name, s = parseNextTagToken(s)

	for len(s) != 0 {
		var token string
		switch token, s = parseNextTagToken(s); token {
		case "omitempty":
			omitempty = true
		case "omitzero":
			omitzero = true
		}
	}

	return Tag{
		Name:      name,
		Omitempty: omitempty,
		Omitzero:  omitzero,
	}
}

