	s := store.Copy()
	defer s.Close()

	var apps []Application
	err := s.C(&Application{}).Find(bson.M{
		coal.F(&Application{}, "Name"): name,
	}).All(&apps)
	if err != nil {
		return "", err
	}

	if len(apps) > 1 {
		return "", errors.New("to many applications with that name")
	} else if len(apps) == 1 {
		return apps[0].Key, nil
	}


	app := coal.Init(&Application{}).(*Application)
	app.Key = key
	app.Name = name
	app.Secret = secret

	err = app.Validate()
	if err != nil {
