			Kind: bson.ElementDocument,
			Data: token,
		}
	}

	s := &Stream{
		store:    store,
		model:    model,
		token:    resumeToken,
		receiver: receiver,
		opened:   opened,
		manager:  manager,
	}

	go s.open()

	return s
}

