	prefix = "/" + strings.Trim(prefix, "/")

	dir := http.Dir(directory)

	fs := http.FileServer(dir)

	h := func(w http.ResponseWriter, r *http.Request) {
		f, err := dir.Open(r.URL.Path)
		if err != nil {
			r.URL.Path = "/"
		} else if f != nil {
			_ = f.Close()
		}

		fs.ServeHTTP(w, r)
	}

	return http.StripPrefix(prefix, http.HandlerFunc(h))
}

