	if p.tasks[task.Name] != nil {
		panic(fmt.Sprintf(`axe: task with name "%s" already exists`, task.Name))
	}

	p.tasks[task.Name] = task

	task.Queue.tasks = append(task.Queue.tasks, task.Name)

