func C(name string, m Matcher, h Handler) *Callback {
	if m == nil || h == nil {
		panic("fire: missing matcher or handler")
	}

	return &Callback{
		Matcher: m,
		Handler: func(ctx *Context) error {
			ctx.Tracer.Push(name)

			err := h(ctx)
			if err != nil {
				return err
			}

			ctx.Tracer.Pop()

			return nil
		},
	}
}

func Only(ops ...Operation) Matcher {
	return func(ctx *Context) bool {
		for _, op := range ops {
			if op == ctx.Operation {
				return true
			}
		}

		return false
	}
}

