func ParseMessageID(s string) (id MessageID, err error) {
	var v uint64
	v, err = strconv.ParseUint(s, 16, 64)
	id = MessageID(v)
	return
}

func (id MessageID) WriteTo(w io.Writer) (int64, error) {
	a := [16]byte{}
	b := strconv.AppendUint(a[:0], uint64(id), 16)
	n := len(a) - len(b)
	copy(a[n:], b)

	for i := 0; i != n; i++ {
		a[i] = '0'
	}

	c, e := w.Write(a[:])
	return int64(c), e
}

