func (rp *redisProvider) refresh(rs *redisStore) error {
	var err error
	redisPool.Exec(func(c *redis.Client) {
		err = c.HMSet(rs.SID, rs.Values).Err()
		if err != nil {
			return
		}
		err = c.Expire(rs.SID, sessExpire).Err()
	})
	return nil
}

