func CompareKV(a []byte, b []byte) int {
	la := int(binary.LittleEndian.Uint16(a[0:2]))
	lb := int(binary.LittleEndian.Uint16(b[0:2]))

	return bytes.Compare(a[2:2+la], b[2:2+lb])
}

