func NewLexer(name, input string, h Handler) *Lexer {
	return &Lexer{
		Name:    name,
		input:   input + "\n",
		state:   lexText,
		handler: h,
	}
}

func (l *Lexer) run() {
	for state := lexText; state != nil; {
		state = state(l)
	}
}

func (l *Lexer) emit(t TokenType) {

	if l.Pos == l.Start {
		return
	}

	tok := Token{t, l.input[l.Start:l.Pos]}
	l.handler(tok)
	l.Start = l.Pos
}

func (l *Lexer) skipWhitespace() {
	for unicode.Is(unicode.White_Space, l.next()) {
	}
	l.backup()
	l.ignore()
}

func (l *Lexer) next() (r rune) {
	if l.Pos >= len(l.input) {
		l.Width = 0
		return eof
	}
	r, l.Width = utf8.DecodeRuneInString(l.remaining())
	l.advance(l.Width)
	return
}

func (l *Lexer) LineNum() int {
	return strings.Count(l.input[:l.Pos], "\n")
}

func (l *Lexer) Offset() int {

	lineoffset := strings.LastIndex(l.input[:l.Pos], "\n")
	if lineoffset != -1 {

		return l.Pos - lineoffset
	}

	return l.Pos
}

func (l *Lexer) errorf(format string, args ...interface{}) stateFn {
	l.handler(Token{TokenError, fmt.Sprintf(fmt.Sprintf("%s[%d:%d] ", l.Name, l.LineNum(), l.Offset())+format, args...)})
	return nil
}

func lexText(l *Lexer) stateFn {
OUTER:
	for {
		l.skipWhitespace()
		remaining := l.remaining()

		if strings.HasPrefix(remaining, comment) {
			return lexComment
		} else if strings.HasPrefix(remaining, pkg) {
			return lexPackage
		} else if strings.HasPrefix(remaining, from) {
			return lexFrom
		} else if strings.HasPrefix(remaining, typeDef) {
			return lexTypeDef
		} else if strings.HasPrefix(remaining, version) {
			return lexVersion
		} else if strings.HasPrefix(remaining, required) {
			l.Pos += len(required)
			l.emit(TokenRequired)
			l.skipWhitespace()

			return lexType
		} else if strings.HasPrefix(remaining, optional) {
			l.Pos += len(optional)
			l.emit(TokenOptional)
			l.skipWhitespace()
			return lexType
		} else if strings.HasPrefix(remaining, openScope) {
			l.Pos += len(openScope)
			l.emit(TokenOpenCurlyBracket)
		} else if strings.HasPrefix(remaining, closeScope) {
			l.Pos += len(closeScope)
			l.emit(TokenCloseCurlyBracket)
		} else {
			switch r := l.next(); {

			case r == eof:
				l.emit(TokenEOF)
				break OUTER
			default:
				l.errorf("unknown token: %#v", string(r))
			}
		}
	}

	return nil
}

func lexComment(l *Lexer) stateFn {
	l.skipWhitespace()

	l.Pos += len(comment)

	if index := strings.Index(l.remaining(), "\n"); index > 0 {
		l.Pos += index
	} else {
		l.Pos += len(l.remaining())
	}

	l.emit(TokenComment)

	l.skipWhitespace()

	return lexText
}

